// ── Helpers ───────────────────────────────────────────────────────────────────
function riskColor(s) {
  if (s <= 25) return '#22c55e';
  if (s <= 50) return '#eab308';
  if (s <= 75) return '#f97316';
  if (s <= 88) return '#ef4444';
  return '#7f1d1d';
}
function riskLabel(s) {
  if (s <= 25) return 'Resilient';
  if (s <= 50) return 'Exposed';
  if (s <= 75) return 'Dependent';
  return 'Structurally Vulnerable';
}
function riskBadgeStyle(s) {
  const c = riskColor(s);
  return `background:${c}1a;color:${c};border:1px solid ${c}40;`;
}
function byISO(iso) { return COUNTRIES.find(c => c.iso === iso); }
function byName(n) { return COUNTRIES.find(c => c.name.toLowerCase() === n.toLowerCase()); }
function lookupFeature(f) {
  const iso  = (f.properties.ISO_A3||f.properties.iso_a3||f.properties.ADM0_A3||'').toUpperCase();
  const name =  f.properties.name||f.properties.NAME||f.properties.ADMIN||'';
  // fix common GeoJSON iso mismatches
  const isoMap = { '-99':'', 'NOR':'NOR','SWE':'SWE' };
  return byISO(iso) || byISO(isoMap[iso]||'') || byName(name) || null;
}

